        {"check_id": "paper_runtime_start_not_performed", "ready": True, "unlock_allowed": False},
        {"check_id": "paper_order_submit_forbidden", "ready": True, "unlock_allowed": False},
        {"check_id": "network_order_submit_forbidden", "ready": True, "unlock_allowed": False},
        {"check_id": "network_request_forbidden", "ready": True, "unlock_allowed": False},
